(function(ctx, state) {
  var sender = ctx.getSender();
  var args = ctx.getArgs();
  var sub = state.helpers.arg(args, 0);
  if (!sub) {
    sender.sendMessage('&6Four Corners commands:');
    sender.sendMessage('&e/four_corners build [size] &7- build a wool arena at your feet &8(&fvibe.four_corners.build&8)');
    sender.sendMessage('&e/four_corners join &7- join the next game &8(&fvibe.four_corners.join&8)');
    sender.sendMessage('&e/four_corners leave &7- leave the queue &8(&fvibe.four_corners.leave&8)');
    sender.sendMessage('&e/four_corners start &7- start with joined players &8(&fvibe.four_corners.start&8)');
    sender.sendMessage('&e/four_corners stop &7- stop the active game &8(&fvibe.four_corners.stop&8)');
    sender.sendMessage('&e/four_corners status &7- show arena/game info &8(&fvibe.four_corners.status&8)');
    sender.sendMessage('&e/four_corners restore &7- restore the blocks replaced by build &8(&fvibe.four_corners.restore&8)');
    return;
  }
  sub = sub.toLowerCase();
  var subPerms = {
    build: 'vibe.four_corners.build',
    setup: 'vibe.four_corners.build',
    join: 'vibe.four_corners.join',
    leave: 'vibe.four_corners.leave',
    start: 'vibe.four_corners.start',
    stop: 'vibe.four_corners.stop',
    end: 'vibe.four_corners.stop',
    status: 'vibe.four_corners.status',
    restore: 'vibe.four_corners.restore',
    undo: 'vibe.four_corners.restore'
  };
  var neededPerm = subPerms[sub];
  if (neededPerm && !sender.hasPermission(neededPerm)) {
    sender.sendMessage('&cYou do not have permission to use that subcommand.');
    sender.sendMessage('&7Required: &e' + neededPerm);
    return;
  }
  if (sub === 'build' || sub === 'setup') {
    if (!sender.isPlayer()) { sender.sendMessage('&cPlayers only.'); return; }
    if (state.game.active) { sender.sendMessage('&cStop the game before rebuilding the arena.'); return; }
    var player = sender.asPlayer();
    var size = state.helpers.num(state.helpers.arg(args, 1), 16);
    if (size < 8) size = 8;
    if (size > 32) size = 32;
    if (size % 2 !== 0) size++;
    if (state.arena && state.arena.snapshots) state.helpers.restoreOriginal(state);
    var loc = player.getLocation();
    var x = Math.floor(loc.getX());
    var y = Math.floor(loc.getY()) - 1;
    var z = Math.floor(loc.getZ());
    var world = player.getWorld();
    state.helpers.captureArena(state, world, x, y, z, size);
    state.helpers.paintPlatform(state);
    player.sendMessage('&aBuilt a &e' + size + 'x' + size + ' &aFour Corners arena at your feet.');
    player.sendMessage('&7Use &e/four_corners join &7then &e/four_corners start&7.');
    try { player.playSound('BLOCK_NOTE_BLOCK_PLING', 1.0, 1.5); } catch (e) {}
    return;
  }
  if (sub === 'join') {
    if (!sender.isPlayer()) { sender.sendMessage('&cPlayers only.'); return; }
    if (!state.arena) { sender.sendMessage('&cBuild an arena first with /four_corners build.'); return; }
    if (state.game.active) { sender.sendMessage('&cA game is already running.'); return; }
    var p = sender.asPlayer();
    state.joined[p.getName()] = true;
    var spawn = state.helpers.arenaSpawn(state, 2);
    if (spawn) p.teleport(spawn);
    sender.sendMessage('&aYou joined Four Corners!');
    state.helpers.broadcastGame(state, '&e' + p.getName() + ' joined. &7(' + state.helpers.joinedPlayers(state).length + ' queued)');
    return;
  }
  if (sub === 'leave') {
    if (!sender.isPlayer()) { sender.sendMessage('&cPlayers only.'); return; }
    var lp = sender.asPlayer();
    if (state.game.active && state.game.alive[lp.getName()]) {
      state.helpers.eliminate(state, lp, 'You left the game.');
    }
    delete state.joined[lp.getName()];
    sender.sendMessage('&eYou left Four Corners.');
    return;
  }
  if (sub === 'start') {
    if (!state.arena) { sender.sendMessage('&cBuild an arena first with /four_corners build.'); return; }
    if (state.game.active) { sender.sendMessage('&cA game is already running.'); return; }
    var players = state.helpers.joinedPlayers(state);
    if (players.length < 2) { sender.sendMessage('&cNeed at least 2 joined online players. Use /four_corners join.'); return; }
    state.helpers.paintPlatform(state);
    state.game.active = true;
    state.game.alive = {};
    state.game.prevModes = {};
    state.game.prevFlight = {};
    state.game.phase = 'safe';
    state.game.round = 0;
    state.game.removed = null;
    state.game.lastRemoved = null;
    state.game.nextAction = Date.now() + state.settings.warningMillis;
    var s = state.helpers.arenaSpawn(state, 2);
    for (var i = 0; i < players.length; i++) {
      var gp = players[i];
      state.game.alive[gp.getName()] = true;
      state.game.prevModes[gp.getName()] = gp.getGameMode();
      state.game.prevFlight[gp.getName()] = gp.getAllowFlight();
      gp.setGameMode('ADVENTURE');
      gp.setAllowFlight(false);
      gp.setFlying(false);
      if (s) gp.teleport(s);
      gp.sendMessage('&aFour Corners started! &7Stand on a color and do not fall.');
      try { gp.playSound('ENTITY_PLAYER_LEVELUP', 0.8, 1.2); } catch (e) {}
    }
    state.helpers.broadcastGame(state, '&aGame started with &e' + players.length + ' &aplayers! Random colors will disappear.');
    return;
  }
  if (sub === 'stop' || sub === 'end') {
    if (!state.game.active) { sender.sendMessage('&cNo Four Corners game is running.'); return; }
    state.helpers.finishGame(state, null);
    sender.sendMessage('&eStopped Four Corners.');
    return;
  }
  if (sub === 'status') {
    sender.sendMessage('&6Four Corners status:');
    sender.sendMessage('&7Arena: ' + (state.arena ? '&a' + state.arena.world + ' &7at &e' + state.arena.x + ',' + state.arena.y + ',' + state.arena.z + ' &7size &e' + state.arena.size : '&cnot built'));
    sender.sendMessage('&7Queued: &e' + state.helpers.joinedPlayers(state).length);
    sender.sendMessage('&7Active: ' + (state.game.active ? '&aYes &7alive: &e' + state.helpers.aliveNames(state).length : '&cNo'));
    return;
  }
  if (sub === 'restore' || sub === 'undo') {
    if (state.game.active) { sender.sendMessage('&cStop the game before restoring the arena.'); return; }
    if (!state.arena) { sender.sendMessage('&cNo arena has been built.'); return; }
    if (state.helpers.restoreOriginal(state)) {
      state.arena = null;
      state.joined = {};
      sender.sendMessage('&aRestored the original blocks and cleared the arena.');
    } else sender.sendMessage('&cCould not restore the arena.');
    return;
  }
  sender.sendMessage('&cUnknown subcommand. Use /four_corners for help.');
})

events.code:
(function(ctx, state) {
  if (!state.game.active || !state.arena) return;
  state.helpers.tick(state);
  var p = ctx.getPlayer();
  if (!p) return;
  var name = p.getName();
  if (!state.game.alive[name]) return;
  var loc = p.getLocation();
  if (loc.getWorldName() !== state.arena.world) {
    state.helpers.eliminate(state, p, 'You left the arena world.');
    return;
  }
  if (loc.getY() < state.arena.y - 2) {
    state.helpers.eliminate(state, p, 'You fell out of the arena.');
  }
})

(function(ctx, state) {
  if (!state.game.active) return;
  var p = ctx.getPlayer();
  if (!p) return;
  if (state.game.alive[p.getName()]) state.helpers.eliminate(state, p, 'You disconnected.');
})

(function(ctx, state) {
  if (!state.arena || !ctx.isCancellable()) return;
  var b = ctx.getBlock();
  if (state.helpers.inArenaBlock(state, b)) {
    ctx.setCancelled(true);
    var p = ctx.getPlayer();
    if (p) p.sendMessage('&cYou cannot break the Four Corners arena.');
  }
})

(function(ctx, state) {
  if (!state.arena || !ctx.isCancellable()) return;
  var b = ctx.getBlock();
  if (state.helpers.inArenaBlock(state, b)) {
    ctx.setCancelled(true);
    var p = ctx.getPlayer();
    if (p) p.sendMessage('&cYou cannot build on the Four Corners arena.');
  }
})
